mapper.update:
UPDATE event.com_grp_cd
SET use_yn = 'N'
   ,updated_by = #{updatedBy,jdbcType=BIGINT}
   ,updated_at = CURRENT_TIMESTAMP
WHERE com_grp_cd = #{comGrpCd}

UPDATE event.com_cd c
SET use_yn = 'N'
   ,updated_by = #{updatedBy,jdbcType=BIGINT}
   ,updated_at = CURRENT_TIMESTAMP
FROM event.com_grp_cd g
WHERE c.com_grp_cd_seq = g.com_grp_cd_seq
  AND g.com_grp_cd = #{comGrpCd}
  AND c.com_cd = #{comCd}
